import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for the fix of the NullPointerException issue with empty THEN blocks.
 * Issue: if-else statement having an empty THEN block causes ktlint to crash.
 */
class MultiLineIfElseRuleEmptyThenBlockTest {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Given an if-else-if-else statement with an empty THEN block in nested if`() {
        val code =
            """
            fun test() {
                if ("a" == "b") {
                } else if ("b" == "c") else {
                }
            }
            """.trimIndent()
        // The code should not crash, even though it's unusual Kotlin code
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an if-else statement with an empty THEN block`() {
        val code =
            """
            fun test() {
                if (true) else {
                    println("else")
                }
            }
            """.trimIndent()
        // The code should not crash
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a nested if-else with empty THEN blocks`() {
        val code =
            """
            fun test() {
                if (true) {
                    if (false) else {
                        println("nested else")
                    }
                }
            }
            """.trimIndent()
        // The code should not crash
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

